# Category: package_integrity

import subprocess

def install_dependencies(lock_file):
    """
    Install dependencies from a given lock file.
    
    :param lock_file: Path to the lock file (requirements.txt or Poetry.lock)
    """
    try:
        print(f"Installing dependencies from {lock_file}...")
        subprocess.check_call(['pip', 'install', '-r', f'--requirement={lock_file}'])
        print("Dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Failed to install dependencies: {e}")

def generate_lock_file(packages):
    """
    Generate a lock file (requirements.txt with hashes) for the given packages.
    
    :param packages: List of package names
    """
    try:
        print("Generating lock file...")
        lock_content = ''
        for package in packages:
            lock_content += f"{package}==\n"
            subprocess.check_call(['pip', 'freeze', '--local', '--upgrade', f'{package}>0'])
            with open(f'__pycache__/temp.lock') as temp_lock_file:
                lock_content += temp_lock_file.read() + '\n'
        with open('requirements.txt', 'w') as requirements_file:
            requirements_file.write(lock_content)
        print("Lock file generated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Failed to generate lock file: {e}")

def generate_poetry_lock(packages):
    """
    Generate a Poetry lock file for the given packages.
    
    :param packages: List of package names
    """
    try:
        print("Generating Poetry lock file...")
        subprocess.check_call(['poetry', 'add', '--dev'] + packages)
        subprocess.check_call(['poetry', 'lock'])
        with open('poetry.lock') as poetry_lock_file:
            content = poetry_lock_file.read()
        with open('requirements.txt', 'w') as requirements_file:
            requirements_file.write(content)
        print("Poetry lock file generated successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Failed to generate Poetry lock file: {e}")

# Usage example
if __name__ == "__main__":
    packages = ['requests', 'numpy']
    
    # Generate lock file (requirements.txt with hashes)
    generate_lock_file(packages)
    
    # Install dependencies from the generated lock file
    install_dependencies('requirements.txt')
    
    # Generate Poetry lock file
    generate_poetry_lock(packages)